SELECT COUNT(*) FROM (

) A

  1=1
  AND A.REGDTM >= #{start_date}
  AND A.REGDTM <= #{end_date} + ' 23:59:59'
  AND A.PLANTCD = #{plant_cd}
  AND A.LOTNO LIKE #{lot_no}
  AND A.PARTNO LIKE #{part_no}
  AND A.PROCESS_STATUS = #{process_status}

SELECT A.LOTNO, A.FAILGUBUN, A.PARTNO, A.PARTNM, A.STANDARD, A.FAILQTY, A.FAILTYPE, A.FAILBREAKDOWN, CONVERT(VARCHAR(10), A.REGDTM, 120) AS REGDATE, A.WORKORDNO, A.LINECD, A.PROCESS_STATUS, A.REMARK FROM (
) A
1=1 AND A.REGDTM >= #{start_date} AND A.REGDTM <= #{end_date} + ' 23:59:59' AND A.PLANTCD = #{plant_cd} AND A.LOTNO LIKE #{lot_no} AND A.PARTNO LIKE #{part_no} AND A.PROCESS_STATUS = #{process_status}
ORDER BY A.REGDTM DESC, A.LOTNO DESC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY
